import{_ as i,o as s,c as e,ae as t}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"Android 앱","description":"Android 앱 (노드): 연결 런북 + Connect/Chat/Voice/Canvas 명령 표면","frontmatter":{"title":"Android 앱","description":"Android 앱 (노드): 연결 런북 + Connect/Chat/Voice/Canvas 명령 표면"},"headers":[],"relativePath":"platforms/android.md","filePath":"platforms/android.md","lastUpdated":null}'),l={name:"platforms/android.md"};function n(o,a,d,p,h,c){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="android-앱-노드" tabindex="-1">Android 앱 (노드) <a class="header-anchor" href="#android-앱-노드" aria-label="Permalink to &quot;Android 앱 (노드)&quot;">​</a></h1><blockquote><p><strong>참고:</strong> Android 앱은 아직 공개 배포되지 않았습니다. 소스 코드는 <code>apps/android</code> 경로 아래 <a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">OpenClaw 저장소</a>에서 확인할 수 있습니다. Java 17과 Android SDK를 사용하여 직접 빌드할 수 있습니다 (<code>./gradlew :app:assemblePlayDebug</code>). 빌드 방법은 <a href="https://github.com/openclaw/openclaw/blob/main/apps/android/README.md" target="_blank" rel="noreferrer">apps/android/README.md</a>를 참조하십시오.</p></blockquote><h2 id="지원-스냅샷" tabindex="-1">지원 스냅샷 <a class="header-anchor" href="#지원-스냅샷" aria-label="Permalink to &quot;지원 스냅샷&quot;">​</a></h2><ul><li>역할: 동반 노드 앱 (Android는 게이트웨이를 호스팅하지 않음).</li><li>게이트웨이 필요 여부: 예 (macOS, Linux, 또는 WSL2를 통한 Windows에서 실행).</li><li>설치: <a href="/openclaw-docs-ko/start/getting-started">시작하기</a> + <a href="/openclaw-docs-ko/channels/pairing">페어링</a>.</li><li>게이트웨이: <a href="/openclaw-docs-ko/gateway">런북</a> + <a href="/openclaw-docs-ko/gateway/configuration">구성</a>. <ul><li>프로토콜: <a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a> (노드 + 제어 플레인).</li></ul></li></ul><h2 id="시스템-제어" tabindex="-1">시스템 제어 <a class="header-anchor" href="#시스템-제어" aria-label="Permalink to &quot;시스템 제어&quot;">​</a></h2><p>시스템 제어 (launchd/systemd)는 게이트웨이 호스트에 있습니다. <a href="/openclaw-docs-ko/gateway">게이트웨이</a>를 참조하십시오.</p><h2 id="연결-런북" tabindex="-1">연결 런북 <a class="header-anchor" href="#연결-런북" aria-label="Permalink to &quot;연결 런북&quot;">​</a></h2><p>Android 노드 앱 ⇄ (mDNS/NSD + WebSocket) ⇄ <strong>게이트웨이</strong></p><p>Android는 게이트웨이 WebSocket에 직접 연결하고 장치 페어링 (<code>role: node</code>)을 사용합니다.</p><p>Tailscale 또는 공용 호스트의 경우 Android에는 보안 엔드포인트가 필요합니다:</p><ul><li>권장: Tailscale Serve / Funnel (<code>https://&amp;lt;magicdns&amp;gt;</code> / <code>wss://&amp;lt;magicdns&amp;gt;</code> 사용)</li><li>지원됨: 실제 TLS 엔드포인트가 있는 다른 <code>wss://</code> 게이트웨이 URL</li><li>평문 <code>ws://</code>는 개인 LAN 주소 / <code>.local</code> 호스트, 그리고 <code>localhost</code>, <code>127.0.0.1</code>, Android 에뮬레이터 브리지 (<code>10.0.2.2</code>)에서 계속 지원됩니다</li></ul><h3 id="사전-요구-사항" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#사전-요구-사항" aria-label="Permalink to &quot;사전 요구 사항&quot;">​</a></h3><ul><li>&quot;마스터&quot; 머신에서 게이트웨이를 실행할 수 있습니다.</li><li>Android 기기/에뮬레이터가 게이트웨이 WebSocket에 도달 가능해야 합니다: <ul><li>mDNS/NSD를 사용하는 동일 LAN, <strong>또는</strong></li><li>Wide-Area Bonjour / 유니캐스트 DNS-SD를 사용하는 동일 Tailscale tailnet (아래 참조), <strong>또는</strong></li><li>수동 게이트웨이 호스트/포트 (대체)</li></ul></li><li>Tailnet/공용 모바일 페어링은 원시 tailnet IP <code>ws://</code> 엔드포인트를 사용하지 <strong>않습니다</strong>. 대신 Tailscale Serve 또는 다른 <code>wss://</code> URL을 사용하십시오.</li><li>게이트웨이 머신에서 CLI (<code>openclaw</code>)를 실행할 수 있습니다 (또는 SSH를 통해).</li></ul><h3 id="_1-게이트웨이-시작" tabindex="-1">1) 게이트웨이 시작 <a class="header-anchor" href="#_1-게이트웨이-시작" aria-label="Permalink to &quot;1) 게이트웨이 시작&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre></div><p>로그에서 다음과 같은 내용이 확인되어야 합니다:</p><ul><li><code>listening on ws://0.0.0.0:18789</code></li></ul><p>Tailscale을 통한 원격 Android 접근의 경우, 원시 tailnet 바인드 대신 Serve/Funnel을 권장합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>이를 통해 Android에 보안 <code>wss://</code> / <code>https://</code> 엔드포인트가 제공됩니다. 단순 <code>gateway.bind: &quot;tailnet&quot;</code> 설정만으로는 TLS를 별도로 종료하지 않는 한 처음 원격 Android 페어링에 충분하지 않습니다.</p><h3 id="_2-검색-확인-선택-사항" tabindex="-1">2) 검색 확인 (선택 사항) <a class="header-anchor" href="#_2-검색-확인-선택-사항" aria-label="Permalink to &quot;2) 검색 확인 (선택 사항)&quot;">​</a></h3><p>게이트웨이 머신에서:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _openclaw-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre></div><p>추가 디버깅 정보: <a href="/openclaw-docs-ko/gateway/bonjour">Bonjour</a>.</p><p>광역 검색 도메인도 구성한 경우 다음과 비교하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discover</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>이 명령은 한 번에 <code>local.</code>과 구성된 광역 도메인을 표시하고, TXT 전용 힌트 대신 확인된 서비스 엔드포인트를 사용합니다.</p><h4 id="tailnet-비엔나-⇄-런던-유니캐스트-dns-sd를-통한-검색" tabindex="-1">Tailnet (비엔나 ⇄ 런던) 유니캐스트 DNS-SD를 통한 검색 <a class="header-anchor" href="#tailnet-비엔나-⇄-런던-유니캐스트-dns-sd를-통한-검색" aria-label="Permalink to &quot;Tailnet (비엔나 ⇄ 런던) 유니캐스트 DNS-SD를 통한 검색&quot;">​</a></h4><p>Android NSD/mDNS 검색은 네트워크를 가로질러 작동하지 않습니다. Android 노드와 게이트웨이가 서로 다른 네트워크에 있지만 Tailscale로 연결된 경우, Wide-Area Bonjour / 유니캐스트 DNS-SD를 사용하십시오.</p><p>검색만으로는 tailnet/공용 Android 페어링에 충분하지 않습니다. 검색된 경로에는 여전히 보안 엔드포인트 (<code>wss://</code> 또는 Tailscale Serve)가 필요합니다:</p><ol><li>게이트웨이 호스트에 DNS-SD 구역 (예: <code>openclaw.internal.</code>)을 설정하고 <code>_openclaw-gw._tcp</code> 레코드를 게시합니다.</li><li>해당 DNS 서버를 가리키는 선택한 도메인에 대한 Tailscale split DNS를 구성합니다.</li></ol><p>세부 사항 및 CoreDNS 구성 예시: <a href="/openclaw-docs-ko/gateway/bonjour">Bonjour</a>.</p><h3 id="_3-android에서-연결" tabindex="-1">3) Android에서 연결 <a class="header-anchor" href="#_3-android에서-연결" aria-label="Permalink to &quot;3) Android에서 연결&quot;">​</a></h3><p>Android 앱에서:</p><ul><li>앱은 <strong>전경 서비스</strong> (지속 알림)를 통해 게이트웨이 연결을 유지합니다.</li><li><strong>Connect</strong> 탭을 엽니다.</li><li><strong>Setup Code</strong> 또는 <strong>Manual</strong> 모드를 사용합니다.</li><li>검색이 차단된 경우 <strong>Advanced controls</strong>에서 수동 호스트/포트를 사용합니다. 개인 LAN 호스트의 경우 <code>ws://</code>가 여전히 작동합니다. Tailscale/공용 호스트의 경우 TLS를 켜고 <code>wss://</code> / Tailscale Serve 엔드포인트를 사용하십시오.</li></ul><p>첫 번째 페어링 성공 후 Android는 시작 시 자동으로 재연결됩니다:</p><ul><li>수동 엔드포인트 (활성화된 경우), 그렇지 않으면</li><li>마지막으로 검색된 게이트웨이 (최선 노력).</li></ul><h3 id="_4-페어링-승인-cli" tabindex="-1">4) 페어링 승인 (CLI) <a class="header-anchor" href="#_4-페어링-승인-cli" aria-label="Permalink to &quot;4) 페어링 승인 (CLI)&quot;">​</a></h3><p>게이트웨이 머신에서:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reject</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>페어링 세부 사항: <a href="/openclaw-docs-ko/channels/pairing">페어링</a>.</p><h3 id="_5-노드-연결-확인" tabindex="-1">5) 노드 연결 확인 <a class="header-anchor" href="#_5-노드-연결-확인" aria-label="Permalink to &quot;5) 노드 연결 확인&quot;">​</a></h3><ul><li><p>노드 상태를 통해:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div></li><li><p>게이트웨이를 통해:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node.list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{}&quot;</span></span></code></pre></div></li></ul><h3 id="_6-채팅-기록" tabindex="-1">6) 채팅 + 기록 <a class="header-anchor" href="#_6-채팅-기록" aria-label="Permalink to &quot;6) 채팅 + 기록&quot;">​</a></h3><p>Android 채팅 탭은 세션 선택을 지원합니다 (기본값 <code>main</code>, 그 외 기존 세션):</p><ul><li>기록: <code>chat.history</code> (표시 정규화; 인라인 지시어 태그는 표시 텍스트에서 제거되고, 일반 텍스트 도구 호출 XML 페이로드 (<code>&amp;lt;tool_call&amp;gt;...&amp;lt;/tool_call&amp;gt;</code>, <code>&amp;lt;function_call&amp;gt;...&amp;lt;/function_call&amp;gt;</code>, <code>&amp;lt;tool_calls&amp;gt;...&amp;lt;/tool_calls&amp;gt;</code>, <code>&amp;lt;function_calls&amp;gt;...&amp;lt;/function_calls&amp;gt;</code> 포함) 및 잘린 도구 호출 블록과 누출된 ASCII/전각 모델 제어 토큰은 제거되며, 정확히 <code>NO_REPLY</code> / <code>no_reply</code>인 순수 무음 토큰 어시스턴트 행은 생략되고, 크기가 큰 행은 플레이스홀더로 교체될 수 있음)</li><li>전송: <code>chat.send</code></li><li>푸시 업데이트 (최선 노력): <code>chat.subscribe</code> → <code>event:&quot;chat&quot;</code></li></ul><h3 id="_7-canvas-카메라" tabindex="-1">7) Canvas + 카메라 <a class="header-anchor" href="#_7-canvas-카메라" aria-label="Permalink to &quot;7) Canvas + 카메라&quot;">​</a></h3><h4 id="게이트웨이-canvas-호스트-웹-콘텐츠에-권장" tabindex="-1">게이트웨이 Canvas 호스트 (웹 콘텐츠에 권장) <a class="header-anchor" href="#게이트웨이-canvas-호스트-웹-콘텐츠에-권장" aria-label="Permalink to &quot;게이트웨이 Canvas 호스트 (웹 콘텐츠에 권장)&quot;">​</a></h4><p>노드에 에이전트가 디스크에서 편집할 수 있는 실제 HTML/CSS/JS를 표시하려면 노드를 게이트웨이 canvas 호스트로 지정하십시오.</p><p>참고: 노드는 게이트웨이 HTTP 서버에서 canvas를 로드합니다 (<code>gateway.port</code>와 동일한 포트, 기본값 <code>18789</code>).</p><ol><li><p>게이트웨이 호스트에 <code>~/.openclaw/workspace/canvas/index.html</code>을 만듭니다.</p></li><li><p>노드를 탐색합니다 (LAN):</p></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> invoke</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&amp;lt;Android Node&amp;gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --command</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> canvas.navigate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;url&quot;:&quot;http://&amp;lt;gateway-hostname&amp;gt;.local:18789/__openclaw__/canvas/&quot;}&#39;</span></span></code></pre></div><p>Tailnet (선택 사항): 두 장치가 모두 Tailscale에 있는 경우, <code>.local</code> 대신 MagicDNS 이름 또는 tailnet IP를 사용하십시오 (예: <code>http://&amp;lt;gateway-magicdns&amp;gt;:18789/__openclaw__/canvas/</code>).</p><p>이 서버는 HTML에 라이브 리로드 클라이언트를 삽입하고 파일 변경 시 리로드합니다. A2UI 호스트는 <code>http://&amp;lt;gateway-host&amp;gt;:18789/__openclaw__/a2ui/</code>에 있습니다.</p><p>Canvas 명령 (전경에서만):</p><ul><li><code>canvas.eval</code>, <code>canvas.snapshot</code>, <code>canvas.navigate</code> (<code>{&quot;url&quot;:&quot;&quot;}</code> 또는 <code>{&quot;url&quot;:&quot;/&quot;}</code> 사용으로 기본 스캐폴드로 돌아감). <code>canvas.snapshot</code>은 <code>{ format, base64 }</code>를 반환합니다 (기본값 <code>format=&quot;jpeg&quot;</code>).</li><li>A2UI: <code>canvas.a2ui.push</code>, <code>canvas.a2ui.reset</code> (<code>canvas.a2ui.pushJSONL</code> 레거시 별칭)</li></ul><p>카메라 명령 (전경에서만; 권한 필요):</p><ul><li><code>camera.snap</code> (jpg)</li><li><code>camera.clip</code> (mp4)</li></ul><p>매개변수 및 CLI 도우미는 <a href="/openclaw-docs-ko/nodes/camera">카메라 노드</a>를 참조하십시오.</p><h3 id="_8-음성-확장된-android-명령-표면" tabindex="-1">8) 음성 + 확장된 Android 명령 표면 <a class="header-anchor" href="#_8-음성-확장된-android-명령-표면" aria-label="Permalink to &quot;8) 음성 + 확장된 Android 명령 표면&quot;">​</a></h3><ul><li>음성: Android는 Voice 탭에서 단일 마이크 켜기/끄기 흐름을 사용하며 전사 캡처 및 <code>talk.speak</code> 재생을 지원합니다. <code>talk.speak</code>를 사용할 수 없는 경우에만 로컬 시스템 TTS가 사용됩니다. 앱이 전경에서 벗어나면 음성이 중지됩니다.</li><li>음성 wake/talk-mode 토글은 현재 Android UX/런타임에서 제거되었습니다.</li><li>추가 Android 명령 패밀리 (기기 + 권한에 따라 가용성이 다름): <ul><li><code>device.status</code>, <code>device.info</code>, <code>device.permissions</code>, <code>device.health</code></li><li><code>notifications.list</code>, <code>notifications.actions</code> (아래 <a href="#알림-전달">알림 전달</a> 참조)</li><li><code>photos.latest</code></li><li><code>contacts.search</code>, <code>contacts.add</code></li><li><code>calendar.events</code>, <code>calendar.add</code></li><li><code>callLog.search</code></li><li><code>sms.search</code></li><li><code>motion.activity</code>, <code>motion.pedometer</code></li></ul></li></ul><h2 id="어시스턴트-진입점" tabindex="-1">어시스턴트 진입점 <a class="header-anchor" href="#어시스턴트-진입점" aria-label="Permalink to &quot;어시스턴트 진입점&quot;">​</a></h2><p>Android는 시스템 어시스턴트 트리거 (Google Assistant)에서 OpenClaw를 시작하는 것을 지원합니다. 구성이 완료되면 홈 버튼을 길게 누르거나 &quot;Hey Google, OpenClaw에게 물어봐...&quot;라고 말하면 앱이 열리고 프롬프트가 채팅 작성기로 전달됩니다.</p><p>이 기능은 앱 매니페스트에 선언된 Android <strong>App Actions</strong> 메타데이터를 사용합니다. 게이트웨이 측에서 추가 구성이 필요하지 않습니다. 어시스턴트 인텐트는 Android 앱에서 완전히 처리되어 일반 채팅 메시지로 전달됩니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>App Actions 가용성은 기기, Google Play Services 버전, 그리고 사용자가 OpenClaw를 기본 어시스턴트 앱으로 설정했는지 여부에 따라 다릅니다.</p></div><h2 id="알림-전달" tabindex="-1">알림 전달 <a class="header-anchor" href="#알림-전달" aria-label="Permalink to &quot;알림 전달&quot;">​</a></h2><p>Android는 장치 알림을 이벤트로 게이트웨이에 전달할 수 있습니다. 여러 제어를 통해 어떤 알림이 언제 전달되는지 범위를 지정할 수 있습니다.</p><table tabindex="0"><thead><tr><th>키</th><th>유형</th><th>설명</th></tr></thead><tbody><tr><td><code>notifications.allowPackages</code></td><td>string[]</td><td>이 패키지 이름의 알림만 전달합니다. 설정된 경우 다른 모든 패키지는 무시됩니다.</td></tr><tr><td><code>notifications.denyPackages</code></td><td>string[]</td><td>이 패키지 이름의 알림은 절대 전달하지 않습니다. <code>allowPackages</code> 이후에 적용됩니다.</td></tr><tr><td><code>notifications.quietHours.start</code></td><td>string (HH:mm)</td><td>방해 금지 시간 시작 (로컬 기기 시간). 이 시간 동안 알림이 억제됩니다.</td></tr><tr><td><code>notifications.quietHours.end</code></td><td>string (HH:mm)</td><td>방해 금지 시간 종료.</td></tr><tr><td><code>notifications.rateLimit</code></td><td>number</td><td>패키지당 분당 최대 전달 알림 수. 초과 알림은 삭제됩니다.</td></tr></tbody></table><p>알림 선택기는 또한 전달된 알림 이벤트에 대해 더 안전한 동작을 사용하여 민감한 시스템 알림의 우발적인 전달을 방지합니다.</p><p>구성 예시:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  notifications</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    allowPackages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.slack&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.whatsapp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    denyPackages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.android.systemui&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    quietHours</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;22:00&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;07:00&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    rateLimit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>알림 전달을 사용하려면 Android 알림 리스너 권한이 필요합니다. 앱은 설정 중에 이 권한을 요청합니다.</p></div>`,72)])])}const g=i(l,[["render",n]]);export{k as __pageData,g as default};
